import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import { gamesAPI } from '../services/api';

interface Game {
  _id: string;
  title: string;
  description: string;
  price: number;
  platform: string;
  region: string;
  images: string[];
  availability: string;
  discount?: number;
  isNew?: boolean;
}

const Home: React.FC = () => {
  const [games, setGames] = useState<Game[]>([]);
  const [loading, setLoading] = useState(true);
  const [filters, setFilters] = useState({
    platform: '',
    region: '',
    priceRange: 'all'
  });
  const { state } = useAuth();

  // دالة لتنسيق الاسم للعرض
  const formatDisplayName = (firstName: string, lastName: string) => {
    if (!firstName && !lastName) return 'مستخدم';

    // إذا كان الاسم بالعربية، نعرضه كما هو
    if (/[\u0600-\u06FF]/.test(firstName) || /[\u0600-\u06FF]/.test(lastName)) {
      return `${firstName} ${lastName}`.trim();
    }

    // إذا كان بالإنجليزية، نعرضه بشكل منسق
    return `${firstName} ${lastName}`.trim();
  };

  useEffect(() => {
    fetchGames();
  }, [filters]);

  const fetchGames = async () => {
    try {
      const response = await gamesAPI.getGames(filters);
      setGames(response.data);
      setLoading(false);
    } catch (error) {
      console.error('Error fetching games:', error);
      setLoading(false);
    }
  };

  return (
    <div className="min-h-screen" style={{ backgroundColor: '#0a0a0a' }}>
      {/* Hero Section */}
      <div className="relative bg-gradient-to-r from-red-900 to-black overflow-hidden">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-16">
          <div className="text-center">
            {state.user ? (
              <>
                <h1 className="text-4xl md:text-6xl font-bold text-white mb-4">
                  أهلاً بك {state.user.firstName} {state.user.lastName}
                </h1>
                <p className="text-xl text-gray-300 mb-8 max-w-3xl mx-auto">
                  مرحباً بك في Alpha Store! استكشف أفضل الألعاب والعروض الحصرية
                </p>
              </>
            ) : (
              <>
                <h1 className="text-4xl md:text-6xl font-bold text-white mb-6">
                  Alpha Store
                </h1>
                <p className="text-xl text-gray-300 mb-8 max-w-3xl mx-auto">
                  أفضل متجر لبيع مفاتيح الألعاب الأصلية بأسعار تنافسية
                </p>
              </>
            )}
            <div className="flex flex-col sm:flex-row gap-4 justify-center">
              {!state.user && (
                <Link
                  to="/register"
                  className="btn-primary text-lg px-8 py-4"
                >
                  إنشاء حساب
                </Link>
              )}
              <Link
                to="/games"
                className="bg-gray-800 text-white px-8 py-4 rounded-lg hover:bg-gray-700 transition-colors text-lg"
              >
                استعرض الألعاب
              </Link>
            </div>
          </div>
        </div>

        {/* Animated background elements */}
        <div className="absolute inset-0 overflow-hidden pointer-events-none">
          <div className="absolute top-20 left-10 w-72 h-72 bg-red-500 rounded-full mix-blend-multiply filter blur-xl opacity-20 animate-pulse"></div>
          <div className="absolute bottom-20 right-10 w-96 h-96 bg-red-600 rounded-full mix-blend-multiply filter blur-2xl opacity-10 animate-pulse"></div>
        </div>
      </div>

      {/* Featured Banner */}
      <div className="bg-gradient-to-r from-red-800 to-red-900 py-8">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
          <div className="card p-6 text-center">
            <div className="flex items-center justify-center mb-4">
              <div className="badge-new">جديد</div>
              <span className="text-white text-2xl font-bold ml-3">عروض حصرية</span>
            </div>
            <p className="text-gray-300 text-lg">
              خصم 20% على جميع مفاتيح Steam و Origin
            </p>
            <p className="text-red-400 font-semibold mt-2">
              لفترة محدودة - استخدم الكود: EN20
            </p>
          </div>
        </div>
      </div>

      {/* Filter Section */}
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        <div className="card p-6">
          <h2 className="text-2xl font-bold text-white mb-6">بحث وتصفية</h2>
          <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
            <div>
              <label className="block text-sm font-medium text-gray-300 mb-2">المنصة</label>
              <select
                value={filters.platform}
                onChange={(e) => setFilters({...filters, platform: e.target.value})}
                className="input-dark w-full"
              >
                <option value="">كل المنصات</option>
                <option value="PC">PC</option>
                <option value="PlayStation">PlayStation</option>
                <option value="Xbox">Xbox</option>
                <option value="Nintendo Switch">Nintendo Switch</option>
                <option value="Mobile">موبايل</option>
              </select>
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-300 mb-2">المنطقة</label>
              <select
                value={filters.region}
                onChange={(e) => setFilters({...filters, region: e.target.value})}
                className="input-dark w-full"
              >
                <option value="">كل المناطق</option>
                <option value="Global">عالمي</option>
                <option value="North America">أمريكا الشمالية</option>
                <option value="Europe">أوروبا</option>
                <option value="Asia">آسيا</option>
                <option value="Middle East">الشرق الأوسط</option>
              </select>
            </div>

            <div>
              <label className="block text-sm font-medium text-gray-300 mb-2">نطاق السعر</label>
              <select
                value={filters.priceRange}
                onChange={(e) => setFilters({...filters, priceRange: e.target.value})}
                className="input-dark w-full"
              >
                <option value="all">كل الأسعار</option>
                <option value="0-25">0 - 25$</option>
                <option value="25-50">25 - 50$</option>
                <option value="50-100">50 - 100$</option>
                <option value="100+">أكثر من 100$</option>
              </select>
            </div>

            <div className="flex items-end">
              <button className="btn-secondary w-full">
                بحث متقدم
              </button>
            </div>
          </div>
        </div>
      </div>

      {/* Products Grid */}
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        <h2 className="text-3xl font-bold text-white mb-8">منتجاتنا</h2>

        {loading ? (
          <div className="text-center py-16">
            <div className="inline-block animate-spin rounded-full h-12 w-12 border-b-2 border-red-600"></div>
            <p className="text-gray-400 mt-4">جاري التحميل...</p>
          </div>
        ) : (
          <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-6">
            {games.map((game) => (
              <div key={game._id} className="card group cursor-pointer">
                {game.isNew && (
                  <div className="badge-new">جديد</div>
                )}

                {game.images && game.images.length > 0 ? (
                  <div className="relative h-48 overflow-hidden">
                    <img
                      src={`http://localhost:5000${game.images[0]}`}
                      alt={game.title}
                      className="w-full h-full object-cover group-hover:scale-110 transition-transform duration-300"
                    />
                    <div className="absolute inset-0 bg-gradient-to-t from-black/70 to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300"></div>
                  </div>
                ) : (
                  <div className="h-48 bg-gradient-to-br from-gray-800 to-gray-900 flex items-center justify-center">
                    <span className="text-gray-400">لا توجد صور</span>
                  </div>
                )}

                <div className="p-4">
                  <div className="flex justify-between items-start mb-2">
                    <h3 className="text-white font-semibold text-lg flex-1">{game.title}</h3>
                    {game.discount && (
                      <span className="discount-badge">-{game.discount}%</span>
                    )}
                  </div>

                  <p className="text-gray-400 text-sm mb-4 line-clamp-2">{game.description}</p>

                  <div className="flex justify-between items-center mb-4">
                    <div className="flex items-center space-x-2">
                      <span className="price-tag">${game.price}</span>
                      {game.discount && (
                        <span className="text-gray-500 line-through text-sm">
                          ${(game.price * (1 + game.discount/100)).toFixed(2)}
                        </span>
                      )}
                    </div>
                    <span className={`px-2 py-1 text-xs rounded-full ${
                      game.availability === 'available' ? 'bg-green-600 text-white' :
                      game.availability === 'sold' ? 'bg-red-600 text-white' :
                      'bg-yellow-600 text-white'
                    }`}>
                      {game.availability === 'available' ? 'متاح' :
                       game.availability === 'sold' ? 'تم البيع' : 'محجوز'}
                    </span>
                  </div>

                  <div className="flex justify-between text-sm text-gray-400 mb-4">
                    <span>{game.platform}</span>
                    <span>{game.region}</span>
                  </div>

                  <div className="flex space-x-2">
                    <Link
                      to={`/game/${game._id}`}
                      className="btn-primary flex-1 text-center"
                    >
                      عرض التفاصيل
                    </Link>
                    <button className="btn-secondary">
                      <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4.318 6.318a4.5 4.5 0 006.364 1.456l4.455 4.455a4.5 4.5 0 00-1.456 6.364L4.318 6.318z" />
                      </svg>
                    </button>
                  </div>
                </div>
              </div>
            ))}
          </div>
        )}

        {!loading && games.length === 0 && (
          <div className="text-center py-16">
            <p className="text-gray-400 text-lg">لا توجد منتجات متاحة حالياً</p>
            <Link
              to="/register"
              className="btn-primary mt-4 inline-block"
            >
              إنشاء حساب جديد
            </Link>
          </div>
        )}
      </div>

      {/* Footer */}
      <footer className="bg-black border-t border-gray-800 py-8 mt-16">
